# SPDX-License-Identifier: MIT
# GNU ld version script for libnirs4all_datasets_capi. Exports only the public
# `n4ds_*` C ABI under the versioned node N4DS_1; everything else is local.
# Wired by build.rs as `-Wl,--version-script=...` on Linux cdylib builds.
# macOS/Windows rely on Rust's default `#[no_mangle]`-only export, asserted in CI
# (.github/workflows/abi-check.yml). Bump the node (N4DS_2, ...) only on an additive
# ABI change; never repurpose an existing symbol.
N4DS_1 {
  global:
    n4ds_*;
  local:
    *;
};
